// daily-digest — agrège la santé de la pipeline n8n sur 24h.
const NOW = Date.now();
const WINDOW_MS = 24 * 60 * 60 * 1000;
const cutoff = NOW - WINDOW_MS;

const dateLabel = new Date(NOW).toLocaleString('fr-FR', {
  timeZone: 'Europe/Paris', day: '2-digit', month: '2-digit',
  hour: '2-digit', minute: '2-digit',
});

const wfResp = $('Fetch workflows').first().json;
const exResp = $('Fetch executions').first().json;

// Chemin dégradé : API n8n injoignable / réponse malformée.
if (!wfResp || !Array.isArray(wfResp.data) || !exResp || !Array.isArray(exResp.data)) {
  return { json: { content: `📊 Ratis n8n — santé pipeline 24h (${dateLabel})\n⚠️ API n8n injoignable — digest indisponible` } };
}

// Map workflowId -> nom.
const nameById = {};
for (const wf of wfResp.data) nameById[wf.id] = wf.name;

// Filtre sur les dernières 24h.
const recent = exResp.data.filter((e) => {
  const t = new Date(e.startedAt).getTime();
  return !Number.isNaN(t) && t >= cutoff;
});

// Agrégation.
const perWorkflow = {};
let failures = 0;
const failingWorkflows = new Set();
let latencySum = 0;
let latencyCount = 0;

for (const e of recent) {
  const name = nameById[e.workflowId] || e.workflowId;
  perWorkflow[name] = (perWorkflow[name] || 0) + 1;
  if (e.status === 'error') {
    failures += 1;
    failingWorkflows.add(name);
  }
  if (e.startedAt && e.stoppedAt) {
    const d = new Date(e.stoppedAt).getTime() - new Date(e.startedAt).getTime();
    if (!Number.isNaN(d) && d >= 0) {
      latencySum += d;
      latencyCount += 1;
    }
  }
}

const total = recent.length;
const avgLatency = latencyCount > 0 ? Math.round(latencySum / latencyCount) : null;

const perWfStr = Object.entries(perWorkflow)
  .map(([n, c]) => `${n} ${c}`)
  .join(' · ') || 'aucune';
const failLine = failures === 0
  ? '• Échecs : 0'
  : `• ⚠️ Échecs : ${failures} (${[...failingWorkflows].join(', ')})`;
const latLine = avgLatency === null
  ? '• Latence moyenne : n/a'
  : `• Latence moyenne : ${avgLatency} ms`;

const content = [
  `📊 Ratis n8n — santé pipeline 24h (${dateLabel})`,
  `• Exécutions : ${total} (${perWfStr})`,
  failLine,
  latLine,
].join('\n');

return { json: { content } };
